(function() {
  // Find the first Samsung T7 product link in the search results
  const results = document.querySelectorAll('[data-component-type="s-search-result"]');
  const firstResult = results[0];
  if (firstResult) {
    const titleLink = firstResult.querySelector('h2 a') || firstResult.querySelector('.a-link-normal.s-no-outline');
    const titleElement = firstResult.querySelector('h2');
    const priceWhole = firstResult.querySelector('.a-price-whole');
    const priceFraction = firstResult.querySelector('.a-price-fraction');

    return JSON.stringify({
      title: titleElement ? titleElement.innerText.trim() : (titleLink ? titleLink.innerText.trim() : null),
      url: titleLink ? titleLink.href : null,
      price: (priceWhole && priceFraction) ? (priceWhole.innerText + priceFraction.innerText).replace(/\n/g, '') : 'unknown'
    });
  }
  return null;
})();

(function() {
  // Get the product title
  const titleElement = document.querySelector('#productTitle');
  const title = titleElement ? titleElement.innerText.trim() : 'unknown';

  // Get the price
  const priceWhole = document.querySelector('.a-price.aok-align-center .a-price-whole');
  const priceFraction = document.querySelector('.a-price.aok-align-center .a-price-fraction');
  let price = 'unknown';

  if (priceWhole) {
    price = '$' + priceWhole.innerText.trim().replace('.', '');
    if (priceFraction) {
      price += '.' + priceFraction.innerText.trim();
    }
  }

  return JSON.stringify({
    status: 'success',
    product_title: title,
    price_text: price
  });
})();

